solution.code:
#include <stdio.h>

int fact(int n) {
    if (n == 0) return 1;
    int r = 1; for(int i=1;i<=n;i++) r*=i; return r;
}

int main() {
    int n = 145, sum = 0, temp = n;
    while(temp>0) { sum += fact(temp%10); temp/=10; }
    if(sum == n) printf("Strong\n");
    return 0;
}
